    n_cols = 4
    result = [[""] * n_cols for _ in range(n_rows)]
    for i in range(n_rows):
        for j in range(n_cols):
            if j == 0:
                result[i][j] = unique_names[i]
            else:
                for row in table:
                    if len(row) >= 2 and row[1] == unique_names[i]:
                        result[i][j] = row[1]
                        break
    return result

